import json
import sys
import os
import re

def main():
    if len(sys.argv) < 2:
        sys.exit(1)

    workspace_root = sys.argv[1]

    # 1. Read retention JSON
    retention_json_path = os.path.join(workspace_root, 'analysis/retention_risk_assessment.json')
    try:
        with open(retention_json_path, 'r') as f:
            retention_data = json.load(f)
    except (FileNotFoundError, json.JSONDecodeError):
        sys.exit(1)

    # 2. Read roster for total nurses
    roster_path = os.path.join(workspace_root, 'nurse_roster_current.md')
    total_nurses = 0
    if os.path.exists(roster_path):
        with open(roster_path, 'r') as f:
            roster_content = f.read()
            # Pattern: Full-Time Staff (11 FTE)
            match = re.search(r"Full-Time Staff \((\d+) FTE\)", roster_content)
            if match:
                total_nurses = int(match.group(1))

    # 3. Read audit for highest hours among at-risk set
    # We can pull this from the audit report table or the retention JSON if it were there, 
    # but the prompt specifically asks to use the audit report to confirm the highest-hours nurse.
    audit_report_path = os.path.join(workspace_root, 'overtime_audit_report.md')
    max_hours_at_risk = 0.0
    if os.path.exists(audit_report_path):
        with open(audit_report_path, 'r') as f:
            lines = f.readlines()
            table_started = False
            for line in lines:
                if "Individual Nurse Comparison" in line:
                    table_started = True
                    continue
                if table_started:
                    if "---" in line or "CareScheduler Avg" in line:
                        continue
                    if "|" in line:
                        cols = [c.strip() for c in line.split("|")]
                        if len(cols) >= 5:
                            try:
                                # Walsh Manual Avg is index 4
                                hours = float(cols[4])
                                if hours > max_hours_at_risk:
                                    max_hours_at_risk = hours
                            except (ValueError, IndexError):
                                continue

    at_risk_count = retention_data.get('at_risk_count', 0)

    if total_nurses == 0:
        sys.exit(1)

    risk_rate_pct = (at_risk_count / total_nurses) * 100

    result = {
        "at_risk_count": at_risk_count,
        "total_nurses": total_nurses,
        "risk_rate_pct": round(risk_rate_pct, 2),
        "highest_hours_at_risk": round(max_hours_at_risk, 2)
    }

    print(json.dumps(result))

if __name__ == "__main__":
    main()
